    CMS_PROJECTS_DELETE = "cms:projects:delete"
    CMS_PROJECTS_PUBLISH = "cms:projects:publish"
    CMS_REVIEWS_READ = "cms:reviews:read"
    CMS_REVIEWS_CREATE = "cms:reviews:create"
    CMS_REVIEWS_UPDATE = "cms:reviews:update"
    CMS_REVIEWS_DELETE = "cms:reviews:delete"
