class AdminSessionInfo(BaseModel):
    """
    Session timing fields returned to cookie-authenticated admin callers.
    All timestamps are UTC epoch seconds (int64). Bearer-token callers do not
    receive this object — it is absent (not null) in the response.

    """

    expires_at: Annotated[
        int,
        Field(
            description="UTC epoch seconds when the server-side session expires. The browser\ncookie MaxAge is derived from the same value. The dashboard should\nuse this to schedule a proactive /refresh call before this deadline.\n"
        ),
    ]
    refresh_at: Annotated[
        int,
        Field(
            description="UTC epoch seconds after which a proactive /refresh call is recommended.\nComputed as access-token expiry minus the server's refresh-leeway,\nclamped to a minimum of now+60s to prevent refresh storms from a\nlarge leeway configuration.\n"
        ),
    ]


class AdminMeResponse(BaseModel):
    """
    Identity and authorisation snapshot for the authenticated admin. Returned
    by `/v1/admin/auth/me` so the dashboard can render role-aware UI without
    hand-rolling a session probe against individual protected endpoints.

    """

    sub: Annotated[
        str,
        Field(description="Stable subject identifier from the Authentik access token."),
    ]
    email: Annotated[
        str,
        Field(
            description="Email claim from the verified token. May be an empty string when the\nupstream IdP omits the claim.\n"
        ),
    ]
    permissions: Annotated[
        list[AdminPermission],
        Field(
            description="Deduplicated, alphabetically-sorted permissions resolved from the\ncaller's Authentik group membership. Empty array when no recognised\nrole bundles matched. Stable string enum — see `AdminPermission`.\n"
        ),
    ]
    session: AdminSessionInfo | None = None


class AdminRefreshResponse(BaseModel):
    """
    Identity, authorisation, and updated session timing returned after a
    proactive admin BFF refresh. The `session` object is always present for
    successful refresh responses because `/refresh` is cookie-auth only.

    """

    sub: Annotated[
        str,
        Field(description="Stable subject identifier from the refreshed access token."),
    ]
    email: Annotated[
        str,
        Field(
            description="Email claim from the verified token. May be an empty string when the\nupstream IdP omits the claim.\n"
        ),
    ]
    permissions: Annotated[
        list[AdminPermission],
        Field(
            description="Deduplicated, alphabetically-sorted permissions resolved from the\nrefreshed access token's group membership.\n"
        ),
    ]
    session: AdminSessionInfo


